import { useState } from "react";

function StatCard({ title, value, color }) {
  return (
    <div
      style={{
        background: "#313244",
        padding: "20px",
        borderRadius: "8px",
        minWidth: "150px",
        borderTop: `4px solid `,
        borderTopColor: color,
      }}
    >
      <h3 style={{ margin: "0 0 10px 0", color: "#a6adc8", fontSize: "14px" }}>
        {title}
      </h3>
      <p
        style={{
          margin: 0,
          fontSize: "28px",
          fontWeight: "bold",
          color: "#cdd6f4",
        }}
      >
        {value}
      </p>
    </div>
  );
}

export default function App() {
  return (
    <div
      style={{
        background: "#1e1e2e",
        color: "#cdd6f4",
        padding: "40px",
        minHeight: "100vh",
        fontFamily: "monospace",
      }}
    >
      <h2>$ htop - system monitor</h2>

      <div
        style={{
          display: "flex",
          gap: "20px",
          flexWrap: "wrap",
          marginTop: "30px",
        }}
      >
        <StatCard title="CPU usage" value="" />

        {/* 3. ТУТ ТВІЙ КОД: 
            Виклич компонент <StatCard /> тричі.
            Передай кожному власні пропси: title, value, color.

            Наприклад:
            <StatCard title="CPU Usage" value="14%" color="#f38ba8" />

            Зроби ще дві картки:
            - Для RAM (наприклад, "3.2 GB" і колір "#a6e3a1")
            - Для Disk (наприклад, "45%" і колір "#89b4fa")
        */}
      </div>
    </div>
  );
}
